module pay
mode governed

glass main() -> Int {
  pour("running");
  return 0;
}

module pay
mode governed

glass approve(x: Int) -> Int
  requires AuthorityClass.AC4
{
  return x;
}

glass main() -> Int {
  pour(approve(1));
  return 0;
}

module pay
mode governed

glass approve(x: Int) -> Int
  requires AuthorityClass.AC3
  requires AuditTrail.Immutable
{
  return x * 2;
}

glass main() -> Int {
  pour(approve(5));
  return 0;
}

module pay
mode governed

glass review(v: Int) -> Int
  requires AuthorityClass.AC2
  requires HumanAppealWindow[30d]
{
  return v;
}

glass main() -> Int {
  pour(review(7));
  return 0;
}

glass bad() -> Int
  requires AuthorityClass.AC9
{
  return 0;
}
glass main() -> Int { return 0; }

enum Status { Pending, Active, Closed }
glass main() -> Int {
  drink s: Any = Status.Active;
  pour(s);
  return 0;
}

struct Point { x: Int, y: Int }
glass main() -> Int {
  drink p: Any = Point([3, 4]);
  pour(p.x);
  pour(p.y);
  return 0;
}

glass main() -> Int {
  drink r: Result[Int, String] = 42;
  pour(r);
  return 0;
}

glass main() -> Int {
  drink g: Governed[Int] = 99;
  pour(g);
  return 0;
}
